//data.rlp-tourismus.de/asset/ac782ff8-fe13-4cd4-814c-0b8a4b28abf6/vXkFyYAs5GeR0uylY48toNiBzULGh0oa2TBs8FnHblA/1773794929/web/entreegebieden_fewo_venetie_en_parijs","autor":"[{'@id': '7aecd595-72ec-4854-823d-fa39cd62618f', '@type': ['Organization', 'dcls:Organization']}]","lizenz":"https://creativecommons.org/publicdomain/zero/1.0/","caption":""},{"url":"https://data.rlp-tourismus.de/asset/5aea80e6-60c8-45d1-b774-93e4db7dffcd/uy9zqN0TGapYTvaMyD4nCE8DR2OKLk6Fm-ew5q3lvS0/1773794929/web/tuinzijde_venetie_en_londen","autor":"[{'@id': '7aecd595-72ec-4854-823d-fa39cd62618f', '@type': ['Organization', 'dcls:Organization']}]","lizenz":"https://creativecommons.org/publicdomain/zero/1.0/","caption":""},{"url":"https://data.rlp-tourismus.de/asset/e6141007-8150-42a2-a981-260e4854ff02/g8-JY7E2XnGbN4F-Td4tDpM0Vh-_rqW3_pxcckeakOs/1773794929/web/kaiserhof","autor":"[{'@id': '7aecd595-72ec-4854-823d-fa39cd62618f', '@type': ['Organization', 'dcls:Organization']}]","lizenz":"https://creativecommons.org/publicdomain/zero/1.0/","caption":""},{"url":"https://data.rlp-tourismus.de/asset/18451fbd-78a2-408e-9adb-672888925ce9/la1ici7Ebha5Dv-6rD1In5hrAJpgmZy36wxfoybRlto/1773794930/web/tuinzijde_amsterdam_berlijn_en_londen","autor":"[{'@id': '7aecd595-72ec-4854-823d-fa39cd62618f', '@type': ['Organization', 'dcls:Organization']}]","lizenz":"https://creativecommons.org/publicdomain/zero/1.0/","caption":""}],"bildLizenz":"https://creativecommons.org/publicdomain/zero/1.0/","bildUrheber":"[{'@id': '7aecd595-72ec-4854-823d-fa39cd62618f', '@type': ['Organization', 'dcls:Organization']}]"},{"id":"dh-a6cf80bf-9fd9-4b5a-a7a6-c5b41ec3b7b0","slug":"ferienhaus-mein-westerwald-2","feratelUuid":"6ee552fc-1a75-460d-b08f-0c7673dc5eca","name":"Ferienhaus \"Mein Westerwald\"","categories":["Ferienhaus","Ferienwohnung / Appartement"],"features":["Westerwald-Steig","Eigener Garten","Satelliten-TV","PKW-Parkplatz","Einstellplatz für Fahrräder","Terrasse","Haustiere willkommen","Frühstücksservice","Nichtraucherhaus","Einzelreisende","Nichtraucher","Familien","Jugendliche","Kinder","Senioren","Westerwald Partner","Ruhige Lage","Englisch","Deutsch","Kinderhochstuhl","Gitterbett / Babybett"],"description":"Gemütliches Holzhaus im „Feriendorf Fohlenwiese“ am Rande des Naturschutzgebietes Holzbachschlucht. Ca. 60 m², für 4-6 Personen, 1 Doppelzimmer (Bett 1,40m breit), 1 Schlafzimmer mit Etagenbett, Wohnzimmer mit Schlafcouch. Holzofen und Gasheizung, Dusche/WC, Küche mit Backofen und Kaffeepadmaschine. Sat-TV, Garten mit Terrasse. Carport und zusätzlicher Autostellplatz. Bettwäsche und Handtücher sind vorhanden. Nichtraucherhaus. Optional auf Absprache: Babybett, Hochstuhl, Grill, Fahrradschuppen. Kurzaufenthalt 1 Nacht möglich, Aufpreis 30,--€. Hunde sind willkommen. Direkt am Westerwald-Steig, idealer Ausgangspunkt für Wanderungen. Strom- und Gaskosten nach Verbrauch.","strasse":"Dappricher Hof B10","plz":"56479","ort":"Seck","bezirk":"WW","lat":50.56843,"lng":8.03791,"contact":{"phone":"(0049) 6436 2850604","email":"info@mein-westerwald.haus","url":"https://www.westerwald.info/tosc5/unterkuenfte#/unterkuenfte/RPT/6ee552fc-1a75-460d-b08f-0c7673dc5eca"},"bild":"https://data.rlp-tourismus.de/asset/fc270f91-79ce-49cb-acf9-5127aad27253/K6Q0Kpr0QqmDKAeniBPhpA0UgZtQ3pSL4dv3msANr8s/1739368500/web/seck04","thumb":"https://data.rlp-tourismus.de/asset/fc270f91-79ce-49cb-acf9-5127aad27253/2Muw0JwKMv-OFhYNZW0S2U42DukgdApk_KtTsIAZV5Q/1739368500/thumb/seck04","bilder":[{"url":"https://data.rlp-tourismus.de/asset/fc270f91-79ce-49cb-acf9-5127aad27253/K6Q0Kpr0QqmDKAeniBPhpA0UgZtQ3pSL4dv3msANr8s/1739368500/web/seck04","autor":"","lizenz":"","caption":"I.Müller"},{"url":"https://data.rlp-tourismus.de/asset/4347aa47-7190-4769-b733-d68ffe4d2d67/-bkrRnXem1CoeWUDKYfHIqE-7H-cQre6Qd0X0joOyBA/1739368500/web/seck01","autor":"","lizenz":"","caption":"I.Müller"},{"url":"https://data.rlp-tourismus.de/asset/fed0623a-7246-4923-803b-a82743358bbb/jrs_oEO_eZQW7m26OXA6dFUbsplien3TondOjht3Imc/1739368500/web/img_1548","autor":"","lizenz":"","caption":"I.Müller"},{"url":"https://data.rlp-tourismus.de/asset/fa2b5812-14ff-43d0-9a06-6faaf7616076/DK53IoorV4TfQb2MMq2cU2iG8BoizARis2aS7UFBErM/1739368500/web/seck06","autor":"","lizenz":"","caption":"I.Müller"},{"url":"https://data.rlp-tourismus.de/asset/10b5f896-d652-4a12-b08b-7a8d65f58f19/R9eplpN70WP9-P0vk6bsN48dhRzItE8w3wy4kqUa9Fs/1739368500/web/seck03","autor":"","lizenz":"","caption":"I.Müller"},{"url":"https://data.rlp-tourismus.de/asset/7a2598a4-2cbe-4d2a-86e9-cf19d3616894/VNDo6d5DB_frpR09VRbtopj-W5bTTjef7qjbecm7vic/1739368500/web/img_1523","autor":"","lizenz":"","caption":"I.Müller"},{"url":"https://data.rlp-tourismus.de/asset/2a750297-0f17-4eed-85dd-7db7cf5d2038/sEipvV73ZmmuQDDZ7KyGU7k6tLgSG87Gg9soelxU8W8/1739368500/web/img_1550","autor":"","lizenz":"","caption":"I. Müller"},{"url":"https://data.rlp-tourismus.de/asset/cf33699e-9eeb-4a20-a45b-2709313afff7/zfLFamyY7RcyFvDZqtgie7oKEL6nHjjStURoHeybSmA/1739368500/web/img_1549","autor":"","lizenz":"","caption":"I. Müller"},{"url":"https://data.rlp-tourismus.de/asset/a816327e-f21b-4570-8ce8-0aa52ddff8b2/WXlTghYVRf-pvtGWoSLyeiLgkzb0tePlmgVWeCqX69w/1739368500/web/img_5648","autor":"","lizenz":"","caption":"I. Müller"},{"url":"https://data.rlp-tourismus.de/asset/d1912f34-f275-4a58-a12d-0c151c9be9f1/Ltc5JNzAGYAnULglgxVO13zvRuR3ytD_yBAtnlaDUag/1739368500/web/img_5650","autor":"","lizenz":"","caption":"I. Müller"},{"url":"https://data.rlp-tourismus.de/asset/46b0176d-cdac-47eb-be8d-4f2037a3a092/MRSPo3OT6cAgXmExN0Whwlp9Nle6yNKHkKSYcNEUKX0/1739368500/web/aussen","autor":"","lizenz":"","caption":"I. Müller"},{"url":"https://data.rlp-tourismus.de/asset/f0e8030a-af73-4cf0-a841-ec51646337d6/Qraky_z4Hu3RB0lLLcR5E-LRBwp85nVBpMig56Zva_o/1739368500/web/img_2110","autor":"","lizenz":"","caption":"I. Müller"},{"url":"https://data.rlp-tourismus.de/asset/fd928498-bda8-40ad-914b-d8f95f7eecc8/9pp9iAB7MSz9uYbwNTsEBeODM7DoSyTDCXGb8Xfs-Ak/1739368500/web/img_5671","autor":"","lizenz":"","caption":"I. Müller"},