//creativecommons.org/publicdomain/zero/1.0/","caption":""},{"url":"https://data.rlp-tourismus.de/asset/29a9399e-7bb5-444f-b8b2-6af4e88ae8df/SVb9lvHhod-JGOq-1_Tc8sEE2W6xVXKVHte2JJLT5M8/1746590199/web/ausblick_aus_dem_schlafzimmer","autor":"[{'@id': '8e184a81-d463-4c63-8203-d70fe4fcf7ee', '@type': ['Organization', 'dcls:Organization']}]","lizenz":"https://creativecommons.org/publicdomain/zero/1.0/","caption":""}],"bildLizenz":"https://creativecommons.org/publicdomain/zero/1.0/","bildUrheber":"[{'@id': '8e184a81-d463-4c63-8203-d70fe4fcf7ee', '@type': ['Organization', 'dcls:Organization']}]"},{"id":"dh-aa0c6b9e-2ebd-41ef-a13c-92db877c718d","slug":"ferienwohnung-happel-dillenburg","feratelUuid":"cb39a7a0-4e1e-4ec2-8a1d-ad48708e773a","name":"Ferienwohnung Interthal Dillenburg","categories":["Ferienwohnung / Appartement"],"features":["WiFi","Terrasse","Waschmaschinenbenutzung mögl.","Einzelreisende","Monteure","Gruppen","Geschäftsreisende","Familien","Rollstuhlfahrer","Barzahlung","Ruhige Lage","Ortsrand"],"description":"Herzlich Willkommen...liebe Gäste und Besucher,\n \nEs freut mich sehr, dass Sie den Weg auf meine Internetseite gefunden haben.\nAuf den folgenden Seiten erhalten Sie einen Einblick in meine Ferienwohnungen, deren Ausstattung und Größe.\n \nIn unserem ruhig gelegenen Wohnhaus können Sie Zeit in einer der schönsten Gegenden des hessischen Mittelgebirges verbringen.\nDie Nähe zu Dillenburg (5km) bietet vor allem niederländischen Besuchern die Gelegenheit in kurzer Zeit die historischen Gemäuer des Wilhelmsturms zu besuchen.\n \nBeide Wohnungen befinden sich im Erdgeschoss und sind für Menschen mit Mobilitätshilfen und Einschränkungen in der Fortbewegung ideal geeignet.\nBesonders im Sommer werden Sie die angenehm kühlen Räumlichkeiten zu Schätzen wissen, wenn Sie von der Sommerhitze geplagt nach Hause kommen.\n \nInformieren Sie sich auch über Nanzenbach, Dillenburg und die verschiedenen Freizeitaktivitäten unserer Region.","strasse":"","plz":"","ort":"","bezirk":null,"lat":50.77184,"lng":8.32617,"contact":{"phone":"","email":"","url":"https://www.westerwald.info/tosc5/unterkuenfte#/unterkuenfte/RPT/cb39a7a0-4e1e-4ec2-8a1d-ad48708e773a"},"bild":"https://data.rlp-tourismus.de/asset/2377c074-5729-46c0-a169-ee7d5160c56b/Agb_nDmPQ2lmCMRZeyauClgIrAgXGdC0Lnl9n8s36Ko/1774325896/web/fewo_29","thumb":"https://data.rlp-tourismus.de/asset/2377c074-5729-46c0-a169-ee7d5160c56b/OSFaJyYctY7JhUru-4kYLxuYOMT0YeqpRtIO0PaLQa8/1774325896/thumb/fewo_29","bilder":[{"url":"https://data.rlp-tourismus.de/asset/2377c074-5729-46c0-a169-ee7d5160c56b/Agb_nDmPQ2lmCMRZeyauClgIrAgXGdC0Lnl9n8s36Ko/1774325896/web/fewo_29","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/63c1124b-e3cc-4925-b3b8-256624bd3b56/COW3cN5D182NaFohF8W11aIANps2A6ev4dCD7LP8Ocw/1774325896/web/fewo_28","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/28dc79c7-2c64-4bf1-9c6d-1b17ee2ba874/W-bermTg7tvGNYwFIP6KVQIAlij2x4_jpDyD529g8fA/1774325897/web/fewo_34_1","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/d614dedc-f380-495f-a448-ea3d835ab1f8/U3KpsHGzRhIm-ews32VThO81hi0NtZUWGNJEkH57DHg/1774325897/web/fewo_34","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/996cb392-ae31-4881-9498-905a6a90f778/0muR7PJ51z8F5evpcBCr0s14HgtnPu-eyOzBO8vMcL4/1774325897/web/fewo_36","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/de617c84-b7b8-4fc4-a87c-3c363ba39207/4f7Oo_BgmBxzReFBtXUvoviVHJYCl5gJ_KrtwwbMaNI/1774325896/web/fewo_32","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/a73e2820-ff5d-4c3b-8120-4726fb06be10/PKxwervAOO3I5KGpdND5ccT-cWJKX35sRyeVo8CUgCE/1774325896/web/fewo_05","autor":"","lizenz":"","caption":""},{"url":"https://data.rlp-tourismus.de/asset/13fd05df-5db1-4b0c-9e9c-35c3c27285d4/c2juGDNpfMmApSquwuDI0G3tww04c-OF3Hb6Acneo9Y/1774325895/web/fewo_04","autor":"","lizenz":"","caption":""},{"url":"https